// =============================================================================
// MULTI-CLIENT TOKEN STORE
// =============================================================================
// One OAuthConnection per email can hold tokens from multiple OAuth clients
// (PebbleFlow friction-free, BYOA private, etc.). These helpers abstract
// over the flat legacy fields and the new tokenClients array.

/**
 * Get the token clients for a connection. If tokenClients is populated, returns
 * it directly. Otherwise synthesizes a single-entry array from flat fields
 * (backward compat for connections created before multi-client support).
 */
export function getTokenClients(conn: OAuthConnection): OAuthTokenClient[] {
  if (conn.tokenClients && conn.tokenClients.length > 0) {
    return conn.tokenClients;
  }
  return [{
    clientId: conn.issuedByClientId || '',
    accessToken: conn.accessToken,
    refreshToken: conn.refreshToken,
    expiresAt: conn.expiresAt,
    scopes: conn.scopes || [],
    authMethod: conn.authMethod || 'web_oauth',
    isByoa: false,
    lastRefreshed: conn.lastRefreshedAt,
  }];
}

/**
 * Update the matching tokenClient entry after a token refresh.
 * Mutates `updatedConnection` in-place. No-op if `originalConnection` has no tokenClients.
 *
 * @param refreshedClientId - The clientId whose tokens were refreshed.
 *   Falls back to `originalConnection.issuedByClientId` when undefined.
 * @param newRefreshToken - Pass `undefined` to leave the existing refreshToken unchanged
 *   (e.g. chrome_identity refreshes don't return refresh tokens).
 * @param newExpiresAt - Pass `undefined` to leave the existing expiresAt unchanged.
 */
export function applyTokenClientUpdate(
  updatedConnection: OAuthConnection,
  originalConnection: OAuthConnection,
  refreshedClientId: string | undefined,
  newAccessToken: string,
  newRefreshToken?: string,
  newExpiresAt?: number,
): void {
  if (!originalConnection.tokenClients?.length) return;
  const clientId = refreshedClientId || originalConnection.issuedByClientId;
  updatedConnection.tokenClients = originalConnection.tokenClients.map(tc =>
    tc.clientId === clientId
      ? {
          ...tc,
          accessToken: newAccessToken,
          ...(newRefreshToken !== undefined && { refreshToken: newRefreshToken }),
          ...(newExpiresAt !== undefined && { expiresAt: newExpiresAt }),
          lastRefreshed: Date.now(),
        }
      : tc
  );
  updatedConnection.scopes = [...new Set(updatedConnection.tokenClients.flatMap(tc => tc.scopes))];
}

// Scope hierarchy: write scopes are supersets of their readonly counterparts.
// A broader granted scope satisfies requirements for a narrower one.
// Drive: drive ⊃ drive.readonly, drive ⊃ drive.file (readonly and file are INCOMPARABLE)
// Workspace editors: documents ⊃ documents.readonly, etc.
const GP = 'https://www.googleapis.com/auth/';
export const SCOPE_SUPERSETS: Record<string, string[]> = {
  // Drive: drive ⊃ drive.readonly; drive ⊃ drive.file
  // NOTE: drive.readonly and drive.file are INCOMPARABLE (readonly=all files read-only,
  // file=app-created/picker-opened read+write). Only full `drive` is a superset of both.
  [`${GP}drive.file`]: [`${GP}drive`],
  [`${GP}drive.readonly`]: [`${GP}drive`],
  [`${GP}documents.readonly`]: [`${GP}documents`],
  [`${GP}spreadsheets.readonly`]: [`${GP}spreadsheets`],
  [`${GP}presentations.readonly`]: [`${GP}presentations`],
  // Calendar: calendar ⊃ calendar.events ⊃ calendar.events.readonly
  //           calendar ⊃ calendar.calendarlist.readonly
  [`${GP}calendar.events.readonly`]: [`${GP}calendar.events`, `${GP}calendar`],
  [`${GP}calendar.events`]: [`${GP}calendar`],
  [`${GP}calendar.calendarlist.readonly`]: [`${GP}calendar`],
  // Gmail: gmail ⊃ gmail.modify ⊃ gmail.readonly
  //        gmail ⊃ gmail.compose, gmail.send, gmail.labels
  [`${GP}gmail.readonly`]: [`${GP}gmail.modify`, `${GP}gmail`],
  [`${GP}gmail.modify`]: [`${GP}gmail`],
  [`${GP}gmail.compose`]: [`${GP}gmail`],
  [`${GP}gmail.send`]: [`${GP}gmail`],
  [`${GP}gmail.labels`]: [`${GP}gmail`],

  // Microsoft Graph scope supersets
  'Mail.Read': ['Mail.ReadWrite'],
  'Mail.Send': ['Mail.ReadWrite'],
  'Calendars.Read': ['Calendars.ReadWrite'],
  'Files.Read': ['Files.ReadWrite', 'Files.ReadWrite.All'],
  'Files.ReadWrite': ['Files.ReadWrite.All'],
  'Tasks.Read': ['Tasks.ReadWrite'],
  'Contacts.Read': ['Contacts.ReadWrite'],
};

/** Check if a granted scope set satisfies a required scope (with superset awareness). */
function scopeSatisfied(grantedScopes: string[], required: string): boolean {
  if (grantedScopes.includes(required)) return true;
  const supersets = SCOPE_SUPERSETS[required];
  return supersets ? supersets.some(broader => grantedScopes.includes(broader)) : false;
}

/**
 * Find the best token client for the given required scopes.
 * Prefers a client that covers ALL required scopes (including via superset matching).
 * Falls back to the client covering the most scopes.
 */
export function getTokenClientForScopes(
  conn: OAuthConnection,
  requiredScopes: string[]
): OAuthTokenClient | undefined {
  const clients = getTokenClients(conn);
  if (clients.length === 0) return undefined;

  // Prefer exact match first (all required scopes present literally)
  const exactMatch = clients.find(tc =>
    requiredScopes.every(s => tc.scopes.includes(s))
  );
  if (exactMatch) return exactMatch;

  // Then try superset match (e.g., drive.readonly satisfying drive.file)
  const supersetMatch = clients.find(tc =>
    requiredScopes.every(s => scopeSatisfied(tc.scopes, s))
  );
  if (supersetMatch) return supersetMatch;

  // Fallback: client covering the most required scopes
  return [...clients].sort((a, b) => {
    const aHits = requiredScopes.filter(s => scopeSatisfied(a.scopes, s)).length;
    const bHits = requiredScopes.filter(s => scopeSatisfied(b.scopes, s)).length;
    return bHits - aHits;
  })[0];
}

/**
 * Merge a new token client into an existing Google connection.
 * If a tokenClient with the same clientId already exists, it is updated.
 * Otherwise the new client is appended. Flat fields (accessToken, scopes, etc.)
 * are kept in sync for backward compatibility.
 */
export function mergeGoogleConnection(
  existing: OAuthConnection,
  newTokenClient: OAuthTokenClient
): OAuthConnection {
  const clients = [...getTokenClients(existing)];
  const idx = clients.findIndex(tc => tc.clientId === newTokenClient.clientId);
  if (idx >= 0) {
    clients[idx] = { ...clients[idx], ...newTokenClient };
  } else {
    clients.push(newTokenClient);
  }

  // Aggregate scopes = union of all tokenClient scopes
  const aggregateScopes = [...new Set(clients.flatMap(tc => tc.scopes))];

  return {
    ...existing,
    tokenClients: clients,
    // Flat fields point to the newly-merged client for backward compat
    accessToken: newTokenClient.accessToken,
    refreshToken: newTokenClient.refreshToken || existing.refreshToken,
    expiresAt: newTokenClient.expiresAt ?? existing.expiresAt,
    scopes: aggregateScopes,
    lastRefreshedAt: Date.now(),
  };
}

/**
 * Remove a token client from a connection by clientId.
 * Recalculates aggregate scopes from remaining clients.
 * If no clients remain, marks connection as expired with empty tokens.
 */
export function removeTokenClientFromConnection(
  connection: OAuthConnection,
  clientId: string
): OAuthConnection {
  const clients = getTokenClients(connection).filter(tc => tc.clientId !== clientId);

  if (clients.length === 0) {
    return {
      ...connection,
      tokenClients: [],
      accessToken: '',
      refreshToken: '',
      scopes: [],
      status: 'expired' as const,
    };
  }

  const aggregateScopes = [...new Set(clients.flatMap(tc => tc.scopes))];
  // Point flat fields to the first remaining client
  const primary = clients[0];

  return {
    ...connection,
    tokenClients: clients,
    accessToken: primary.accessToken,
    refreshToken: primary.refreshToken || connection.refreshToken,
    expiresAt: primary.expiresAt ?? connection.expiresAt,
    scopes: aggregateScopes,
    issuedByClientId: primary.clientId,
  };
}

/**
 * Upsert a connection into a list.
 *
 * Match key is `(provider, email, issuedByClientId)` for every provider — each
 * distinct OAuth client ID gets its own row, even when the underlying Google
 * or Microsoft account (email) is the same. Rationale: BYOA ("Bring Your Own
 * App") lets a user authenticate the same identity through multiple OAuth
 * clients (PebbleFlow's verified app + their own Cloud/Azure app), and the
 * agent-facing `OAuthConnection.label` is what disambiguates them at tool
 * call time. Collapsing into a single row with a `tokenClients[]` array (the
 * pre-2026-04-22 design) caused refresh-desync, cross-client scope
 * accounting, and revocation bugs.
 *
 * Legacy connections that still have multi-element `tokenClients` continue
 * to be read via `getTokenClients()`; this function simply stops creating
 * new merged rows.
 */
export function upsertConnectionInList(
  existingConnections: OAuthConnection[],
  newConnection: OAuthConnection
): OAuthConnection[] {
  const match = existingConnections.find(c =>
    !c.deleted &&
    c.provider === newConnection.provider &&
    c.email === newConnection.email &&
    c.issuedByClientId === newConnection.issuedByClientId
  );

  if (!match) {
    return [...existingConnections, newConnection];
  }

  // Same (provider, email, issuedByClientId) → idempotent replace
  return existingConnections.map(c => c.id === match.id ? newConnection : c);
}

