/**
 * Provider configuration for OAuth flows
 */
export interface OAuthProviderConfig {
  provider: OAuthProvider;
  clientId: string;
  clientSecret?: string; // Required for Web application type clients
  scopes: string[];
  authUrl: string;
  tokenUrl: string;
  userInfoUrl?: string;
  // Web client ID for server/Safari OAuth flow
  // Requires webClientSecret for Web application type clients
  webClientId?: string;
  webClientSecret?: string; // Required for Google "Web application" type clients
  webRedirectUri?: string;
  // Provider-specific options
  options?: Record<string, unknown>;
}

/**
 * Result of adding a new connection
 */
export interface AddConnectionResult {
  success: boolean;
  connection?: OAuthConnection;
  error?: string;
  /** Warning message (e.g., GitHub scope limitations) - connection succeeded but with caveats */
  warning?: string;
}

/**
 * Result of refreshing a connection
 */
export interface RefreshConnectionResult {
  success: boolean;
  connection?: OAuthConnection;
  error?: string;
}

/**
 * Connection health status
 */
export interface ConnectionHealth {
  connectionId: string;
  provider: OAuthProvider;
  status: OAuthConnectionStatus;
  isTokenExpired: boolean;
  canRefresh: boolean;
  lastChecked: number;
}

// =============================================================================
// HELPER FUNCTIONS
// =============================================================================

/**
 * Get localhost OAuth redirect URI for web OAuth popup flow.
 * Always returns localhost because:
 * 1. Web OAuth popup opens a regular browser window
 * 2. Google redirects to this URI after auth
 * 3. We poll the popup URL to detect redirect and extract the code
 * 4. Google allows localhost for installed/desktop applications
 */
function getWebOAuthRedirectUri(): string {
  // IMPORTANT: Always use DEFAULT_RELAY_PORT (3847) to avoid redirect_uri_mismatch errors.
  // The actual server may run on a different port if 3847 is busy, but OAuth redirect URIs
  // must be pre-registered in Google Cloud Console. Using a fixed port means we only need
  // to register http://localhost:3847/oauth/callback once.
  return `http://localhost:${DEFAULT_RELAY_PORT}/oauth/callback`;
}

/**
 * Detect if we need to open OAuth in a system browser instead of a popup.
 * WebViews (WKWebView, Android WebView, Tauri) can't use window.open() popups.
 * Instead, we open OAuth in system browser and receive callback via WebSocket.
 */
function isWKWebView(): boolean {
  // Native app WebView can't do popup OAuth — must use system browser
  if (isNativeAppContext()) return true;

  // Tauri desktop app — webview can't do popup OAuth, must use system browser
  if (!isServerContext() && (window as any).__TAURI__) return true;

  // macOS native sidepanel (WKWebView on localhost)
  if (isLocalRelayConnection() && isNativeMacOS()) return true;

  return false;
}

/**
 * Open URL in the system browser via the cross-platform openExternalUrl abstraction.
 * Handles WKWebView (webkit messageHandlers), Tauri (plugin-shell), extension
 * (chrome.tabs), and browser (window.open) contexts automatically.
 */
function openInSystemBrowser(url: string): void {
  openExternalUrl(url).catch((e: Error) => {
    logger.error('[ConnectionsManager] Failed to open URL externally:', e);
  });
}

