// isExtensionContext is imported from runtime-context.ts

/**
 * Get OAuth token using chrome.identity.launchWebAuthFlow (for non-Google or account selection)
 * This allows selecting any account, not just the Chrome profile
 * Only works in extension context.
 */
async function getWebAuthFlowToken(
  provider: OAuthProvider,
  scopes: string[],
  interactive: boolean = true,
  byoa?: { byoaClientId?: string; byoaClientSecret?: string }
): Promise<{ accessToken: string; refreshToken?: string; email?: string; name?: string; providerId?: string; providerData?: Record<string, unknown> } | null> {
  // This function requires chrome.identity.launchWebAuthFlow
  if (!chromeApis.hasLaunchWebAuthFlow()) {
    logger.debug('[Auth] chrome.identity.launchWebAuthFlow not available, cannot use web auth flow');
    return null;
  }

  // For Google, get client ID from manifest (always available)
  // For other providers, require configuration
  let clientId: string;
  let authUrl: string;

  const metadata = PROVIDER_REGISTRY[provider];

  // BYOA overrides every other clientId source (manifest, config, defaults).
  if (byoa?.byoaClientId) {
    clientId = byoa.byoaClientId;
    authUrl = metadata?.authUrl || (provider === 'google' ? 'https://accounts.google.com/o/oauth2/v2/auth' : '');
    if (!authUrl) {
      throw new Error(`BYOA: unknown auth URL for provider ${provider}`);
    }
  } else if (provider === 'google') {
    // Google uses client ID from manifest.json oauth2 section
    // No client secret needed - Chrome identity API handles token exchange internally
    const manifest = chrome.runtime.getManifest();
    const oauth2Config = (manifest as { oauth2?: { client_id?: string } }).oauth2;
    if (!oauth2Config?.client_id) {
      throw new Error('Google OAuth not configured in manifest');
    }
    clientId = oauth2Config.client_id;
    authUrl = 'https://accounts.google.com/o/oauth2/v2/auth';
  } else {
    const config = getProviderConfig(provider);
    if (!config) {
      if (metadata) {
        throw new Error(
          `${metadata.name} is not configured yet. ` +
          `OAuth client ID required for ${metadata.name} integration. ` +
          `Please configure this provider in settings or contact support.`
        );
      }
      throw new Error(`Unknown provider: ${provider}`);
    }
    clientId = config.clientId;
    authUrl = config.authUrl;
  }

  const redirectUri = chrome.identity.getRedirectURL();
  const state = generateSecureId('oauth_state');
  const nonce = generateSecureId('nonce');

  // Generate PKCE for secure authorization code exchange
  const { codeVerifier, codeChallenge } = await generatePKCE();

  const scopeParamName = metadata?.scopeParamName || 'scope';
  const params = new URLSearchParams({
    client_id: clientId,
    redirect_uri: redirectUri,
    response_type: 'code', // Authorization code flow with PKCE (not implicit)
    [scopeParamName]: scopes.join(' '),
    state,
    nonce,
    code_challenge: codeChallenge,
    code_challenge_method: 'S256',
    // Force account selection for identity providers
    ...(provider === 'google' && { prompt: 'consent', access_type: 'offline' }),
    ...(provider === 'microsoft' && { response_mode: 'query', prompt: 'select_account' }),
  });

  // If provider has separate bot scopes (e.g., Slack), add them under the standard 'scope' param
  if (metadata?.botScopes?.length && scopeParamName !== 'scope') {
    params.set('scope', metadata.botScopes.join(' '));
  }

  const fullAuthUrl = `${authUrl}?${params.toString()}`;

  return new Promise((resolve, reject) => {
    chrome.identity.launchWebAuthFlow(
      { url: fullAuthUrl, interactive },
      async (responseUrl) => {
        if (chrome.runtime.lastError) {
          reject(chrome.runtime.lastError);
          return;
        }
        if (!responseUrl) {
          resolve(null);
          return;
        }

        // Parse authorization code from URL query (PKCE flow)
        const url = new URL(responseUrl);
        const code = url.searchParams.get('code');

        if (!code) {
          // Check for error in response
          const error = url.searchParams.get('error');
          if (error) {
            reject(new Error(`OAuth error: ${error}`));
            return;
          }
          reject(new Error('No authorization code in response'));
          return;
        }

        try {
          // Exchange code for tokens using PKCE. BYOA forces direct exchange
          // with the user-supplied secret; PF-owned clients route through the relay.
          const tokens = await exchangeCodeForTokens(provider, code, codeVerifier, redirectUri, clientId, {
            clientSecret: byoa?.byoaClientSecret,
          });

          // Validate nonce in id_token if present
          if (tokens.idToken) {
            if (!validateIdTokenNonce(tokens.idToken, nonce)) {
              reject(new Error('OAuth security error: nonce validation failed'));
              return;
            }
          }

          // Fetch user info if possible (uses provider-specific logic for Slack, GitHub, etc.)
          const userInfo = await fetchUserInfo(provider, tokens.accessToken).catch(() => null);
          resolve({
            accessToken: tokens.accessToken,
            refreshToken: tokens.refreshToken,
            email: userInfo?.email,
            name: userInfo?.name,
            providerId: userInfo?.providerId,
            providerData: tokens.providerData,
          });
        } catch (exchangeError) {
          reject(exchangeError);
        }
      }
    );
  });
}

/**
 * Get OAuth token for Google using chrome.identity.launchWebAuthFlow
 * This is used when adding a different account (not the Chrome profile)
 * Supports login_hint parameter to pre-select the account
 * Uses PKCE for secure authorization code exchange without client secret
 *
 * IMPORTANT: This requires a Web OAuth client ID with the chromiumapp.org redirect URI
 * registered in Google Cloud Console. The manifest oauth2.client_id is for Chrome apps
 * and doesn't support launchWebAuthFlow redirect URIs.
 */
async function getGoogleWebAuthFlowToken(
  scopes: string[],
  interactive: boolean = true,
  loginHint?: string,
  byoaClientId?: string,
  byoaClientSecret?: string,
): Promise<{ accessToken: string; refreshToken?: string; email?: string; name?: string; providerId?: string } | null> {
  // This function requires chrome.identity.launchWebAuthFlow
  if (!chromeApis.hasLaunchWebAuthFlow()) {
    logger.debug('[Auth] chrome.identity.launchWebAuthFlow not available, cannot use web auth flow');
    return null;
  }

  let clientId: string;

  // BYOA overrides any configured or manifest client.
  if (byoaClientId) {
    clientId = byoaClientId;
  } else {
    // Check if there's a web client ID configured
    const config = getProviderConfig('google');
    if (config?.webClientId) {
      // Use configured web client ID (recommended)
      clientId = config.webClientId;
    } else {
      // Fall back to manifest client ID (may not work with launchWebAuthFlow)
      const manifest = chrome.runtime.getManifest();
      const oauth2Config = (manifest as { oauth2?: { client_id?: string } }).oauth2;
      if (!oauth2Config?.client_id) {
        throw new Error('Google OAuth not configured in manifest');
      }
      clientId = oauth2Config.client_id;
      logger.warn(
          '[OAuth] Using manifest client_id for launchWebAuthFlow. ' +
          'This may fail with redirect_uri_mismatch. ' +
          'Configure a Web OAuth client with chromiumapp.org redirect URI for best results.'
        );
    }
  }

  const redirectUri = chrome.identity.getRedirectURL();
  const state = generateSecureId('oauth_state');
  const nonce = generateSecureId('nonce');

  // Generate PKCE for secure authorization code exchange
  const { codeVerifier, codeChallenge } = await generatePKCE();

  // Log for debugging redirect_uri_mismatch errors
  logger.debug('[OAuth] Google Web Auth Flow - redirect_uri:', redirectUri);
  logger.debug('[OAuth] Google Web Auth Flow - client_id:', clientId);

  // Last-mile gate: strip BYOA-only scopes when using PF's client ID.
  // This prevents PF's unverified app from requesting restricted scopes
  // regardless of how the caller constructed the scope list.
  const sanitizedScopes = sanitizeGoogleScopesForClient(scopes, clientId);

  const params = new URLSearchParams({
    client_id: clientId,
    redirect_uri: redirectUri,
    response_type: 'code', // Authorization code flow with PKCE (not implicit)
    scope: sanitizedScopes.join(' '),
    state,
    nonce,
    code_challenge: codeChallenge,
    code_challenge_method: 'S256',
    // IMPORTANT: Use 'consent' to ensure Google returns a refresh token
    // 'select_account' alone only shows account picker but doesn't force consent,
    // and Google only returns refresh_token on first consent or when re-consenting
    prompt: 'consent',
    access_type: 'offline', // Request refresh token
  });

  // Add login_hint if provided - this pre-selects the account in Google's UI
  if (loginHint) {
    params.set('login_hint', loginHint);
  }

  const fullAuthUrl = `https://accounts.google.com/o/oauth2/v2/auth?${params.toString()}`;

  return new Promise((resolve, reject) => {
    chrome.identity.launchWebAuthFlow(
      { url: fullAuthUrl, interactive },
      async (responseUrl) => {
        if (chrome.runtime.lastError) {
          const errorMessage = chrome.runtime.lastError.message || '';
          // Provide helpful error message for redirect_uri_mismatch
          if (errorMessage.includes('redirect_uri_mismatch') ||
              errorMessage.includes('invalid_request') ||
              errorMessage.includes('Authorization page could not be loaded')) {
            reject(new Error(
              'OAuth configuration error: The redirect URI is not registered. ' +
              'Please add a Web OAuth client in Google Cloud Console with redirect URI: ' +
              redirectUri
            ));
            return;
          }
          reject(chrome.runtime.lastError);
          return;
        }
        if (!responseUrl) {
          resolve(null);
          return;
        }

        // Parse authorization code from URL query (PKCE flow)
        const url = new URL(responseUrl);
        const code = url.searchParams.get('code');

        if (!code) {
          const error = url.searchParams.get('error');
          if (error) {
            reject(new Error(`OAuth error: ${error}`));
            return;
          }
          reject(new Error('No authorization code in response'));
          return;
        }

        try {
          // Exchange code for tokens using PKCE. BYOA forces direct exchange
          // with the user-supplied secret; PF-owned clients route through the relay.
          const tokens = await exchangeCodeForTokens('google', code, codeVerifier, redirectUri, clientId, {
            clientSecret: byoaClientSecret,
          });

          // Validate nonce in id_token if present
          if (tokens.idToken) {
            if (!validateIdTokenNonce(tokens.idToken, nonce)) {
              reject(new Error('OAuth security error: nonce validation failed'));
              return;
            }
          }

          // Fetch user info from Google
          let email: string | undefined;
          let name: string | undefined;
          let providerId: string | undefined;

          try {
            const response = await fetch('https://www.googleapis.com/oauth2/v3/userinfo', {
              headers: { Authorization: `Bearer ${tokens.accessToken}` },
            });
            if (response.ok) {
              const userInfo = await response.json();
              email = userInfo.email;
              name = userInfo.name;
              providerId = userInfo.sub;
              logger.info('[OAuth] Userinfo fetched:', email, name);
            } else {
              logger.warn('[OAuth] Userinfo fetch returned:', response.status, await response.text().catch(() => ''));
            }
          } catch (err) {
            logger.warn('[OAuth] Userinfo fetch failed:', err instanceof Error ? err.message : String(err));
          }

          // Fallback: extract user info from id_token if userinfo fetch failed
          // Google's id_token always contains email/name/sub when those scopes are granted
          if (!email && tokens.idToken) {
            const payload = decodeJwtPayload(tokens.idToken);
            if (payload) {
              email = email || (payload.email as string | undefined);
              name = name || (payload.name as string | undefined);
              providerId = providerId || (payload.sub as string | undefined);
              if (email) {
                logger.debug('[OAuth] Extracted user info from id_token:', email);
              }
            }
          }

          // Verify we got the expected account if loginHint was provided
          if (loginHint && email &&
              email.toLowerCase() !== loginHint.toLowerCase()) {
            logger.warn(
              `[OAuth] Connected as ${email}, but ${loginHint} was requested. ` +
              'User may have selected a different account.'
            );
            // Don't reject - let the user add whichever account they selected
          }

          resolve({
            accessToken: tokens.accessToken,
            refreshToken: tokens.refreshToken,
            email,
            name,
            providerId,
          });
        } catch (exchangeError) {
          reject(exchangeError);
        }
      }
    );
  });
}

/**
 * Get OAuth token using chrome.identity.launchWebAuthFlow (extension context).
 *
 * All providers now go through launchWebAuthFlow (the Chrome-profile-only
 * getAuthToken path was removed along with chrome_identity support — it had
 * no refresh-token story outside the extension).
 */
async function getExtensionOAuthToken(
  provider: OAuthProvider,
  scopes: string[],
  interactive: boolean = true,
  options?: {
    loginHint?: string; // Email hint for account selection
    byoaClientId?: string;
    byoaClientSecret?: string;
  }
): Promise<{ accessToken: string; refreshToken?: string; email?: string; name?: string; providerId?: string; providerData?: Record<string, unknown> } | null> {
  if (!chromeApis.hasLaunchWebAuthFlow()) {
    logger.debug('[Auth] chrome.identity.launchWebAuthFlow not available for provider:', provider);
    return null;
  }

  if (provider === 'google') {
    return getGoogleWebAuthFlowToken(scopes, interactive, options?.loginHint, options?.byoaClientId, options?.byoaClientSecret);
  }

  return getWebAuthFlowToken(provider, scopes, interactive, {
    byoaClientId: options?.byoaClientId,
    byoaClientSecret: options?.byoaClientSecret,
  });
}

/**
 * Initiate OAuth flow to add a new connection.
 *
 * - Extension context: chrome.identity.launchWebAuthFlow + PKCE → web_oauth connection.
 * - Native app context (iOS): platform OAuth handler (ASWebAuthenticationSession).
 * - Web/relay context: popup OAuth with localhost redirect.
 *
 * `forceWebFlow` is kept for call-site compatibility but is now a no-op —
 * launchWebAuthFlow is always used in extension context. The old
 * chrome.identity.getAuthToken path (Chrome profile only) was removed along
 * with chrome_identity support.
 */
export async function initiateConnection(
  provider: OAuthProvider,
  options?: {
    scopes?: string[];
    label?: string;
    usePopup?: boolean;
    redirectUri?: string;
    state?: string;
    /** @deprecated No-op. Retained for call-site compatibility. */
    forceWebFlow?: boolean;
    loginHint?: string;
    /**
     * BYOA: user-registered OAuth client ID. When supplied, the flow uses
     * this clientId instead of PebbleFlow's default, looks up the paired
     * `client_secret` from `userGoogleOAuthApps` / `userMicrosoftOAuthApps`,
     * and bypasses the Cloudflare relay for all token exchanges.
     */
    byoaClientId?: string;
  }
): Promise<{ authUrl: string; state: string } | { connection: OAuthConnection }> {
  const requestedScopes = options?.scopes
    ?? getProviderConfig(provider)?.scopes
    ?? DEFAULT_PROVIDER_SCOPES[provider]
    ?? [];
  // Always include identity scopes for Google so userinfo returns email/name/sub.
  // Without these, tool-specific scopes (e.g., calendar-only) cause Google to omit
  // id_token and userinfo email, resulting in connections with no email displayed.
  const scopes = provider === 'google'
    ? [...new Set([...GOOGLE_IDENTITY_SCOPES, ...requestedScopes])]
    : requestedScopes;
  const config = getProviderConfig(provider);

  // Resolve BYOA client ID + secret once; all three dispatch paths below use them.
  let byoaSecret: string | undefined;
  if (options?.byoaClientId) {
    const settings = await getStorageAdapter().getSettings().catch(() => undefined);
    byoaSecret = getByoaClientSecret(options.byoaClientId, settings);
    if (!byoaSecret) {
      throw new Error(
        `BYOA OAuth app ${options.byoaClientId} has no stored client_secret. ` +
        `Re-run the Add Custom Provider wizard to register it.`
      );
    }
  }

  // ==========================================================================
  // CHROME EXTENSION CONTEXT — launchWebAuthFlow + PKCE (web_oauth)
  // ==========================================================================
  if (chromeApis.hasLaunchWebAuthFlow()) {
    const result = await getExtensionOAuthToken(provider, scopes, true, {
      loginHint: options?.loginHint,
      byoaClientId: options?.byoaClientId,
      byoaClientSecret: byoaSecret,
    });

    if (!result) {
      throw new Error('OAuth flow cancelled or failed');
    }

    // Stamp the clientId that actually issued the tokens so refresh routes correctly.
    const extensionClientId = options?.byoaClientId || config?.webClientId || config?.clientId || undefined;

    return {
      connection: createOAuthConnection(
        provider,
        result.providerId || result.email || generateId('provider'),
        result.email || '',
        result.accessToken,
        scopes,
        {
          name: result.name,
          label: options?.label,
          refreshToken: result.refreshToken,
          expiresAt: computeTokenExpiresAt(provider),
          authMethod: 'web_oauth',
          issuedByClientId: extensionClientId,
          metadata: result.providerData,
        }
      ),
    };
  }

  // ==========================================================================
  // NATIVE APP CONTEXT (iOS) - Use platform OAuth handler (ASWebAuthenticationSession)
  // ==========================================================================
  if (isNativeAppContext() && platformOAuthHandler) {
    if (options?.byoaClientId) {
      // The native platform handler signs auth requests using a built-in iOS
      // client; it does not currently accept a BYOA override. Fail loud rather
      // than silently falling back to PF's identity.
      throw new Error('BYOA OAuth is not supported on iOS / native app context yet.');
    }
    return platformOAuthHandler(provider, scopes, {
      label: options?.label,
      loginHint: options?.loginHint,
    });
  }

  // ==========================================================================
  // WEB/RELAY CONTEXT - Use popup OAuth with localhost redirect
  // ==========================================================================
  // Used when not in Chrome extension (Safari, server/relay, standalone web)
  // Web popup works because opener and redirect are same origin (localhost)

  if (!config && !options?.byoaClientId) {
    throw new Error(`Provider ${provider} not configured. Call configureProvider() first.`);
  }

  const clientId = options?.byoaClientId || config!.webClientId || config!.clientId;
  const redirectUri = getWebOAuthRedirectUri();

  // Use popup flow for immediate connection
  return initiateWebOAuthPopup(provider, clientId, scopes, {
    label: options?.label,
    redirectUri,
    loginHint: options?.loginHint,
    clientSecret: byoaSecret,
  });
}

// generatePKCE imported from ../pkce-utils

/**
 * Decode JWT payload without verification (for extracting claims)
 * Note: This does NOT verify the signature - only use for nonce validation
 * where we're checking our own generated values
 */
function decodeJwtPayload(jwt: string): Record<string, unknown> | null {
  try {
    const parts = jwt.split('.');
    if (parts.length !== 3) return null;
    const payload = parts[1];
    // Base64url decode
    const decoded = atob(payload.replace(/-/g, '+').replace(/_/g, '/'));
    return JSON.parse(decoded);
  } catch {
    return null;
  }
}

/**
 * Validate nonce in id_token matches the expected nonce
 * This prevents replay attacks in OpenID Connect flows
 */
function validateIdTokenNonce(idToken: string, expectedNonce: string): boolean {
  const payload = decodeJwtPayload(idToken);
  if (!payload) {
    logger.warn('[OAuth] Could not decode id_token for nonce validation');
    return false;
  }

  const tokenNonce = payload.nonce as string | undefined;
  if (!tokenNonce) {
    // Some providers may not include nonce even when requested
    logger.warn('[OAuth] id_token missing nonce claim');
    return true; // Don't fail if provider doesn't support nonce
  }

  if (tokenNonce !== expectedNonce) {
    logger.error('[OAuth] Nonce mismatch! Expected:', expectedNonce.substring(0, 4) + '...', 'Got:', tokenNonce.substring(0, 4) + '...');
    return false;
  }

  logger.debug('[OAuth] Nonce validated successfully');
  return true;
}

/**
 * Exchange authorization code for tokens using PKCE.
 *
 * Routing rules:
 *  - `options.clientSecret` supplied → **always direct** to the provider's
 *    token endpoint. This is the BYOA path: the user's secret lives on the
 *    device and must never touch the PebbleFlow relay.
 *  - No secret + provider in `RELAY_PROXIED_PROVIDERS` → proxy through the
 *    Cloudflare relay, which injects PF's server-side secret.
 *  - No secret + provider not proxied → direct exchange with whatever
 *    `client_secret` `getProviderConfig` has (legacy user-configured apps).
 */
export async function exchangeCodeForTokens(
  provider: OAuthProvider,
  code: string,
  codeVerifier: string,
  redirectUri: string,
  clientId: string,
  options?: { clientSecret?: string },
): Promise<{ accessToken: string; refreshToken?: string; expiresIn?: number; idToken?: string; providerData?: Record<string, unknown> }> {
  const metadata = PROVIDER_REGISTRY[provider];
  if (!metadata) {
    throw new Error(`Unknown provider: ${provider}`);
  }

  // BYOA path: caller-supplied client_secret wins; otherwise self-resolve from
  // the BYOA registry when `clientId` belongs to a user-registered app. This
  // keeps the incremental-scope paths (requestChromeIdentityIncrementalScopes,
  // requestTabOAuthIncrementalScopes) correct for BYOA connections — they
  // pass the connection's clientId but don't know whether it's BYOA.
  let byoaSecret = options?.clientSecret;
  if (!byoaSecret) {
    try {
      const settings = await getStorageAdapter().getSettings();
      byoaSecret = getByoaClientSecret(clientId, settings);
    } catch {
      // No settings available — fall through to legacy routing.
    }
  }
  const useDirectExchange = !!byoaSecret || !RELAY_PROXIED_PROVIDERS.has(provider);

  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), 15_000);
  let response: Response;
  try {
    if (!useDirectExchange) {
      // PebbleFlow-owned provider — proxy through relay (secret injected server-side)
      response = await fetch(`${PRIVATE_RELAY_BASE_URL}/api/oauth/token`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },
        body: JSON.stringify({
          provider,
          client_id: clientId,
          grant_type: 'authorization_code',
          code,
          code_verifier: codeVerifier,
          redirect_uri: redirectUri,
        }),
        signal: controller.signal,
      });
    } else {
      // Direct exchange: BYOA or legacy user-configured provider
      const body: Record<string, string> = {
        client_id: clientId,
        code,
        code_verifier: codeVerifier,
        grant_type: 'authorization_code',
        redirect_uri: redirectUri,
      };

      // BYOA secret takes precedence; fall back to the provider config's secret
      // for legacy user-configured (non-proxied) providers.
      const secret = byoaSecret ?? (() => {
        const config = getProviderConfig(provider);
        return config?.clientSecret || config?.webClientSecret;
      })();
      if (secret) body.client_secret = secret;

      response = await fetch(metadata.tokenUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          // GitHub requires Accept: application/json to return JSON instead of form-urlencoded
          'Accept': 'application/json',
        },
        body: new URLSearchParams(body),
        signal: controller.signal,
      });
    }
  } catch (err) {
    if (err instanceof DOMException && err.name === 'AbortError') {
      throw new Error('Token exchange timed out after 15 seconds');
    }
    throw err;
  } finally {
    clearTimeout(timeoutId);
  }

  if (!response.ok) {
    const error = await response.text();
    throw new Error(`Token exchange failed: ${error}`);
  }

  const data = await response.json();

  // Slack V2 OAuth returns user token nested in authed_user, not at top level
  if (provider === 'slack') {
    if (!data.ok) throw new Error(`Slack OAuth error: ${data.error || 'unknown'}`);
    const authedUser = data.authed_user;
    return {
      accessToken: authedUser?.access_token || data.access_token,
      refreshToken: data.refresh_token,
      expiresIn: data.expires_in,
      providerData: {
        botToken: data.access_token, // xoxb-... bot token (top-level)
        userId: authedUser?.id,
        teamId: data.team?.id,
        teamName: data.team?.name,
      },
    };
  }

  return {
    accessToken: data.access_token,
    refreshToken: data.refresh_token,
    expiresIn: data.expires_in,
    idToken: data.id_token, // OpenID Connect id_token for nonce validation
  };
}

/**
 * Initiate OAuth using a popup window (for server/Safari context)
 * Uses authorization code flow with PKCE to get refresh tokens
 */
async function initiateWebOAuthPopup(
  provider: OAuthProvider,
  clientId: string,
  scopes: string[],
  options?: {
    label?: string;
    redirectUri?: string;
    loginHint?: string; // Email hint to pre-select account
    /** BYOA: user-supplied `client_secret`. Forces direct token exchange. */
    clientSecret?: string;
  }
): Promise<{ connection: OAuthConnection; warning?: string }> {
  const metadata = PROVIDER_REGISTRY[provider];
  if (!metadata) {
    throw new Error(`Unknown provider: ${provider}`);
  }

  // For popup flow, always use localhost redirect (Google allows for installed apps)
  const redirectUri = options?.redirectUri || getWebOAuthRedirectUri();
  const state = generateSecureId('oauth_state');
  const nonce = generateSecureId('nonce');

  // Generate PKCE for secure code exchange without client secret
  const { codeVerifier, codeChallenge } = await generatePKCE();

  // Last-mile gate: strip BYOA-only scopes when using PF's client ID.
  const sanitizedScopes = provider === 'google'
    ? sanitizeGoogleScopesForClient(scopes, clientId)
    : scopes;
  const byoaClientSecret = options?.clientSecret;

  const scopeParamName = metadata.scopeParamName || 'scope';
  const params = new URLSearchParams({
    client_id: clientId,
    redirect_uri: redirectUri,
    response_type: 'code', // Authorization code flow with PKCE
    [scopeParamName]: sanitizedScopes.join(' '),
    state,
    nonce,
    code_challenge: codeChallenge,
    code_challenge_method: 'S256',
    // Apply provider-specific auth params (e.g., access_type: 'offline' for Google)
    ...(metadata.authParams || {}),
  });

  // If provider has separate bot scopes (e.g., Slack), add them under the standard 'scope' param
  if (metadata.botScopes?.length && scopeParamName !== 'scope') {
    params.set('scope', metadata.botScopes.join(' '));
  }

  // For web OAuth popup flow ("Add Different Account"), show account chooser.
  // Do NOT use include_granted_scopes — it causes Google to show consent for ALL
  // 22 previously-granted scopes, not just the ones we're requesting.
  // The scopes parameter already contains what we need: for re-auth, thread.tsx
  // merges existing connection scopes; for new accounts (account_not_found),
  // only the JIT-required scopes are passed.
  if (provider === 'google') {
    params.set('prompt', 'select_account');
  }

  // Add login_hint if provided - pre-fills the email in the account chooser
  if (options?.loginHint) {
    params.set('login_hint', options.loginHint);
  }

  const authUrl = `${metadata.authUrl}?${params.toString()}`;

  // Debug logging for OAuth flow
  logger.info(`[OAuth] Starting ${provider} OAuth flow with scopes:`, scopes);
  if (provider === 'github') {
    logger.info('[OAuth] GitHub auth URL (for debugging):', authUrl);
  }

  return new Promise((resolve, reject) => {
    // For WKWebView (macOS/iOS app), open in system browser and wait for WebSocket callback
    if (isWKWebView()) {
      logger.debug('[ConnectionsManager] WKWebView detected, opening OAuth in system browser');
      openInSystemBrowser(authUrl);

      let resolved = false;
      const cleanup = () => {
        resolved = true;
        window.removeEventListener('message', handleMessage);
        window.removeEventListener('pebbleflow-oauth-result', handleCustomEvent as unknown as EventListener);
      };

      // Handle OAUTH_CALLBACK_RESULT from relay server (via WebSocket/transport)
      const handleMessage = async (event: MessageEvent) => {
        if (resolved) return;

        // Handle OAUTH_CALLBACK_RESULT broadcast from server
        if (event.data?.type === 'OAUTH_CALLBACK_RESULT' && event.data.payload) {
          const payload = event.data.payload;
          logger.debug('[ConnectionsManager] Received OAuth callback via WebSocket:', { hasCode: !!payload.code, hasError: !!payload.error });

          // Check if this callback matches our state
          if (payload.state && payload.state !== state) {
            logger.debug('[ConnectionsManager] OAuth callback state mismatch, ignoring');
            return;
          }

          cleanup();

          if (payload.error) {
            reject(new Error(`OAuth error: ${payload.error}`));
            return;
          }

          if (!payload.code) {
            reject(new Error('No authorization code in OAuth response'));
            return;
          }

          try {
            // Exchange authorization code for tokens using PKCE
            const tokens = await exchangeCodeForTokens(provider, payload.code, codeVerifier, redirectUri, clientId, {
              clientSecret: byoaClientSecret,
            });

            // Validate nonce in id_token if present
            if (tokens.idToken) {
              if (!validateIdTokenNonce(tokens.idToken, nonce)) {
                throw new Error('OAuth security error: nonce validation failed');
              }
            }

            // Fetch user info with the new access token
            let userInfo = await fetchUserInfo(provider, tokens.accessToken).catch(() => null);

            // Fallback: extract user info from id_token if userinfo fetch failed
            if (!userInfo?.email && tokens.idToken) {
              const payload2 = decodeJwtPayload(tokens.idToken);
              if (payload2?.email) {
                userInfo = {
                  email: payload2.email as string,
                  name: (userInfo?.name || payload2.name) as string | undefined,
                  providerId: (userInfo?.providerId || payload2.sub) as string | undefined,
                };
              }
            }

            // Verify actual granted scopes (GitHub via header, Google via tokeninfo, others pass-through)
            const { scopes: actualScopes, warning: scopeWarning } = await resolveActualScopes(
              provider,
              tokens.accessToken,
              scopes,
            );

            const connection = createOAuthConnection(
              provider,
              userInfo?.providerId || userInfo?.email || generateId('provider'),
              userInfo?.email || '',
              tokens.accessToken,
              actualScopes,
              {
                name: userInfo?.name,
                label: options?.label,
                refreshToken: tokens.refreshToken,
                expiresAt: computeTokenExpiresAt(provider, tokens.expiresIn),
                authMethod: 'web_oauth',
                issuedByClientId: clientId,
                metadata: tokens.providerData,
              }
            );

            // If there's a scope warning, include it in the result
            if (scopeWarning) {
              resolve({ connection, warning: scopeWarning });
            } else {
              resolve({ connection });
            }
          } catch (err) {
            reject(err instanceof Error ? err : new Error(String(err)));
          }
        }
      };

      // Also listen for custom event (dispatched by transport layer)
      const handleCustomEvent = async (event: CustomEvent) => {
        if (resolved) return;
        const payload = event.detail;
        if (payload?.code || payload?.error) {
          // Forward to handleMessage via synthetic MessageEvent
          handleMessage({ data: { type: 'OAUTH_CALLBACK_RESULT', payload } } as MessageEvent);
        }
      };

      window.addEventListener('message', handleMessage);
      window.addEventListener('pebbleflow-oauth-result', handleCustomEvent as unknown as EventListener);

      // Timeout after 5 minutes
      setTimeout(() => {
        if (!resolved) {
          cleanup();
          reject(new Error('OAuth timeout - please try again'));
        }
      }, 5 * 60 * 1000);

      return;
    }

    // Standard popup flow for browsers
    const popup = window.open(
      authUrl,
      `${provider}-oauth`,
      'width=500,height=700,scrollbars=yes,resizable=yes'
    );

    if (!popup) {
      reject(new Error('Failed to open OAuth popup. Please allow popups for this site.'));
      return;
    }

    // Shared resolved flag + cleanup for both poll loop and WebSocket fallback
    let popupResolved = false;
    const cleanupPopup = () => {
      popupResolved = true;
      clearInterval(pollInterval);
      window.removeEventListener('pebbleflow-oauth-result', handlePopupCustomEvent as unknown as EventListener);
    };

    // Helper: exchange code for tokens and create connection (shared by poll + WebSocket paths)
    const handleAuthCode = async (code: string) => {
      try {
        const tokens = await exchangeCodeForTokens(provider, code, codeVerifier, redirectUri, clientId, {
          clientSecret: byoaClientSecret,
        });

        // Validate nonce in id_token if present (OpenID Connect security)
        if (tokens.idToken) {
          if (!validateIdTokenNonce(tokens.idToken, nonce)) {
            throw new Error('OAuth security error: nonce validation failed');
          }
        }

        // Fetch user info with the new access token
        let userInfo = await fetchUserInfo(provider, tokens.accessToken).catch(() => null);

        // Fallback: extract user info from id_token if userinfo fetch failed
        if (!userInfo?.email && tokens.idToken) {
          const idPayload = decodeJwtPayload(tokens.idToken);
          if (idPayload?.email) {
            userInfo = {
              email: idPayload.email as string,
              name: (userInfo?.name || idPayload.name) as string | undefined,
              providerId: (userInfo?.providerId || idPayload.sub) as string | undefined,
            };
          }
        }

        // Verify actual granted scopes (GitHub via header, Google via tokeninfo, others pass-through)
        const { scopes: actualScopes, warning: scopeWarning } = await resolveActualScopes(
          provider,
          tokens.accessToken,
          scopes,
        );

        const connection = createOAuthConnection(
          provider,
          userInfo?.providerId || userInfo?.email || generateId('provider'),
          userInfo?.email || '',
          tokens.accessToken,
          actualScopes,
          {
            name: userInfo?.name,
            label: options?.label,
            refreshToken: tokens.refreshToken,
            expiresAt: computeTokenExpiresAt(provider, tokens.expiresIn),
            authMethod: 'web_oauth',
            issuedByClientId: clientId,
            metadata: tokens.providerData,
          }
        );
        logger.debug('[OAuth] Connection created with refresh token:', !!tokens.refreshToken);

        if (scopeWarning) {
          resolve({ connection, warning: scopeWarning });
        } else {
          resolve({ connection });
        }
      } catch (err) {
        logger.error('[OAuth] Token exchange failed:', err);
        reject(err instanceof Error ? err : new Error(`Token exchange failed: ${String(err)}`));
      }
    };

    // WebSocket fallback: listen for pebbleflow-oauth-result custom event.
    // When COOP headers sever the popup reference, the relay server broadcasts
    // the OAuth result via WebSocket → this custom event delivers it.
    const handlePopupCustomEvent = (event: CustomEvent) => {
      if (popupResolved) return;
      const payload = event.detail;
      if (!payload?.code && !payload?.error) return;

      // Security: only accept results matching our OAuth state parameter
      if (payload.state && payload.state !== state) {
        logger.debug('[OAuth] WebSocket callback state mismatch, ignoring');
        return;
      }

      cleanupPopup();
      try { popup.close(); } catch { /* COOP - can't close */ }

      if (payload.error) {
        reject(new Error(`OAuth error: ${payload.error}`));
        return;
      }

      if (!payload.code) {
        reject(new Error('No authorization code in OAuth response'));
        return;
      }

      logger.debug('[OAuth] Received OAuth result via WebSocket fallback');
      handleAuthCode(payload.code);
    };

    window.addEventListener('pebbleflow-oauth-result', handlePopupCustomEvent as unknown as EventListener);

    // Poll for popup close and check for authorization code in URL
    const pollInterval = setInterval(() => {
      try {
        if (popupResolved) {
          clearInterval(pollInterval);
          return;
        }

        if (popup.closed) {
          cleanupPopup();
          reject(new Error('OAuth popup was closed'));
          return;
        }

        // Try to read the popup URL (will throw if cross-origin)
        const popupUrl = popup.location.href;

        // Check if we're on the redirect URI with a code
        if (popupUrl.startsWith(redirectUri)) {
          cleanupPopup();
          popup.close();

          // Parse authorization code from URL query string (code flow)
          const url = new URL(popupUrl);
          const code = url.searchParams.get('code');
          const error = url.searchParams.get('error');

          if (error) {
            reject(new Error(`OAuth error: ${error}`));
            return;
          }

          if (!code) {
            reject(new Error('No authorization code in OAuth response'));
            return;
          }

          handleAuthCode(code);
        }
      } catch {
        // Cross-origin error - popup is on OAuth provider's domain, keep waiting
      }
    }, 500);

    // Timeout after 5 minutes
    setTimeout(() => {
      if (popupResolved) return;
      cleanupPopup();
      try {
        if (!popup.closed) {
          popup.close();
        }
      } catch {
        // COOP violation - popup is cross-origin, can't check closed state
      }
      reject(new Error('OAuth timeout - please try again'));
    }, 5 * 60 * 1000);
  });
}

/**
 * Fetch user info from provider
 */
async function fetchUserInfo(
  provider: OAuthProvider,
  accessToken: string
): Promise<{ email?: string; name?: string; providerId?: string } | null> {
  const metadata = PROVIDER_REGISTRY[provider];
  if (!metadata?.userInfoUrl) {
    return null;
  }

  try {
    // Slack requires two API calls: auth.test (identity) + users.info (profile/email)
    if (provider === 'slack') {
      const testResp = await fetch('https://slack.com/api/auth.test', {
        headers: { Authorization: `Bearer ${accessToken}` },
      });
      const testData = await testResp.json();
      if (!testData.ok) return null;

      // users.info gives us email and profile details
      const userResp = await fetch(`https://slack.com/api/users.info?user=${testData.user_id}`, {
        headers: { Authorization: `Bearer ${accessToken}` },
      });
      const userData = await userResp.json();
      const profile = userData.user?.profile;

      return {
        providerId: testData.user_id,
        email: profile?.email || '',
        name: profile?.real_name || profile?.display_name,
      };
    }

    const response = await fetch(metadata.userInfoUrl, {
      headers: {
        Authorization: `Bearer ${accessToken}`,
        // GitHub API requires Accept header
        ...(provider === 'github' ? { 'Accept': 'application/vnd.github.v3+json' } : {}),
      },
    });

    if (!response.ok) {
      return null;
    }

    const data = await response.json();
    let email = data.email || data.mail;

    // GitHub: /user often returns null email when the user's email is private.
    // The user:email scope grants access via the separate /user/emails endpoint.
    if (!email && provider === 'github') {
      try {
        const emailsResponse = await fetch('https://api.github.com/user/emails', {
          headers: {
            Authorization: `Bearer ${accessToken}`,
            'Accept': 'application/vnd.github.v3+json',
          },
        });
        if (emailsResponse.ok) {
          const emails = await emailsResponse.json();
          // Prefer primary email, fall back to first verified email
          const primary = emails.find((e: any) => e.primary && e.verified);
          const verified = emails.find((e: any) => e.verified);
          email = primary?.email || verified?.email || emails[0]?.email;
        }
      } catch {
        // Non-critical — proceed without email
      }
    }

    return {
      email,
      name: data.name || data.displayName,
      providerId: data.sub || data.id || data.oid,
    };
  } catch {
    return null;
  }
}

/**
 * Verify GitHub OAuth scopes by making an API request and checking the X-OAuth-Scopes header.
 * GitHub returns the actual granted scopes in every API response header.
 *
 * @param accessToken - The GitHub access token to verify
 * @param requestedScopes - The scopes that were originally requested
 * @returns Object with actual granted scopes and any missing critical scopes
 */
async function verifyGitHubScopes(
  accessToken: string,
  requestedScopes: string[]
): Promise<{
  grantedScopes: string[];
  missingScopes: string[];
  hasCriticalMissing: boolean;
  warning?: string;
}> {
  // Critical scopes that significantly impact functionality
  const CRITICAL_SCOPES = ['repo']; // repo is needed for private repository access

  try {
    // Make a simple API call to get the X-OAuth-Scopes header
    const response = await fetch('https://api.github.com/user', {
      headers: {
        'Authorization': `Bearer ${accessToken}`,
        'Accept': 'application/vnd.github.v3+json',
        'X-GitHub-Api-Version': '2022-11-28',
      },
    });

    if (!response.ok) {
      logger.warn('[OAuth] GitHub scope verification failed - API returned:', response.status);
      // Return requested scopes as fallback (assume they were granted)
      return {
        grantedScopes: requestedScopes,
        missingScopes: [],
        hasCriticalMissing: false,
      };
    }

    // Extract actual granted scopes from header
    const scopeHeader = response.headers.get('X-OAuth-Scopes');
    const grantedScopes = scopeHeader
      ? scopeHeader.split(',').map(s => s.trim()).filter(Boolean)
      : [];

    logger.debug('[OAuth] GitHub scope verification - requested:', requestedScopes, 'granted:', grantedScopes);

    // Check for missing scopes
    const grantedSet = new Set(grantedScopes);
    const missingScopes = requestedScopes.filter(scope => !grantedSet.has(scope));
    const missingCritical = CRITICAL_SCOPES.filter(scope =>
      requestedScopes.includes(scope) && !grantedSet.has(scope)
    );

    let warning: string | undefined;
    if (missingCritical.length > 0) {
      warning = `GitHub access is limited: Missing '${missingCritical.join(', ')}' permission. ` +
        `Private repositories will not be accessible. ` +
        `To fix: Go to GitHub Settings → Applications → Authorized OAuth Apps → PebbleFlow → Revoke, ` +
        `then reconnect in PebbleFlow.`;
      logger.warn('[OAuth] GitHub missing critical scopes:', missingCritical);
    } else if (missingScopes.length > 0) {
      logger.info('[OAuth] GitHub missing non-critical scopes:', missingScopes);
    }

    return {
      grantedScopes,
      missingScopes,
      hasCriticalMissing: missingCritical.length > 0,
      warning,
    };
  } catch (error) {
    logger.warn('[OAuth] GitHub scope verification error:', error);
    // Return requested scopes as fallback
    return {
      grantedScopes: requestedScopes,
      missingScopes: [],
      hasCriticalMissing: false,
    };
  }
}

/**
 * Verify Google OAuth scopes by calling the tokeninfo endpoint.
 * Google's tokeninfo returns the actual granted scopes for the token, which may
 * differ from what we requested (user may have unchecked a box on the consent
 * screen, or Google may have downgraded the grant). We persist the real list so
 * the proactive JIT scope check (connectionHasScopes) doesn't trust a lie.
 *
 * On any failure (network error, non-OK response, missing scope field) we fall
 * back to the requested scopes — a bad-connect path shouldn't lock the user
 * out. `verified: false` tells the caller the result is unverified.
 */
export async function verifyGoogleScopes(
  accessToken: string,
  requestedScopes: readonly string[],
): Promise<{
  grantedScopes: string[];
  missingScopes: string[];
  verified: boolean;
}> {
  const SCOPE_ALIASES: Record<string, string> = {
    email: 'https://www.googleapis.com/auth/userinfo.email',
    profile: 'https://www.googleapis.com/auth/userinfo.profile',
  };

  const fallback = (): {
    grantedScopes: string[];
    missingScopes: string[];
    verified: boolean;
  } => ({
    grantedScopes: [...requestedScopes],
    missingScopes: [],
    verified: false,
  });

  try {
    const response = await fetch(
      `https://www.googleapis.com/oauth2/v3/tokeninfo?access_token=${encodeURIComponent(accessToken)}`,
    );
    if (!response.ok) {
      logger.warn('[OAuth] Google scope verification failed - tokeninfo status:', response.status);
      return fallback();
    }
    const tokenInfo = await response.json();
    const scopeField: string = typeof tokenInfo?.scope === 'string' ? tokenInfo.scope : '';
    if (!scopeField) {
      logger.warn('[OAuth] Google tokeninfo returned no scope field');
      return fallback();
    }
    const grantedScopes = scopeField.split(' ').map(s => s.trim()).filter(Boolean);

    // Expand alias equivalence in BOTH directions so a requested 'email' matches
    // a granted long-form URL (and vice-versa).
    const normalizedGranted = new Set(grantedScopes);
    for (const [shortForm, longForm] of Object.entries(SCOPE_ALIASES)) {
      if (normalizedGranted.has(longForm)) normalizedGranted.add(shortForm);
      if (normalizedGranted.has(shortForm)) normalizedGranted.add(longForm);
    }

    const missingScopes = requestedScopes.filter(scope => !normalizedGranted.has(scope));

    if (missingScopes.length > 0) {
      logger.warn('[OAuth] Google granted scopes differ from requested. missing:', missingScopes, 'granted:', grantedScopes);
    } else {
      logger.debug('[OAuth] Google scope verification ok — granted:', grantedScopes.length, 'scopes');
    }

    return {
      grantedScopes,
      missingScopes,
      verified: true,
    };
  } catch (error) {
    logger.warn('[OAuth] Google scope verification error:', error);
    return fallback();
  }
}

/**
 * Resolve the scopes that should be persisted on a newly-minted connection.
 * Providers that expose a scope-verification endpoint (GitHub via header,
 * Google via tokeninfo) are consulted so the stored scope list reflects what
 * the token actually has, not just what we asked for. Everyone else gets the
 * requested list through unchanged.
 */
export async function resolveActualScopes(
  provider: OAuthProvider,
  accessToken: string,
  requestedScopes: string[],
): Promise<{ scopes: string[]; warning?: string }> {
  if (provider === 'github') {
    const v = await verifyGitHubScopes(accessToken, requestedScopes);
    return {
      scopes: v.grantedScopes.length > 0 ? v.grantedScopes : requestedScopes,
      warning: v.warning,
    };
  }
  if (provider === 'google') {
    const v = await verifyGoogleScopes(accessToken, requestedScopes);
    // When tokeninfo is unreachable we intentionally fall back to the requested
    // list (verified:false). Using granted here is safe either way — fallback
    // makes granted === requested.
    return { scopes: v.grantedScopes };
  }
  return { scopes: requestedScopes };
}

/**
 * Handle OAuth callback and create connection
 */
export async function handleOAuthCallback(
  code: string,
  state: string,
  options?: {
    backendUrl?: string; // URL to exchange code for tokens (server-side)
  }
): Promise<AddConnectionResult> {
  // Retrieve stored state
  const storedStateJson = sessionStorage.getItem(`oauth_state_${state}`);

  if (!storedStateJson) {
    return { success: false, error: 'Invalid or expired OAuth state' };
  }

  const storedState = JSON.parse(storedStateJson) as {
    provider: OAuthProvider;
    label?: string;
    scopes: string[];
    redirectUri: string;
    createdAt: number;
  };

  // Clean up state
  sessionStorage.removeItem(`oauth_state_${state}`);

  // Check if state is too old (5 minutes)
  if (Date.now() - storedState.createdAt > 5 * 60 * 1000) {
    return { success: false, error: 'OAuth state expired' };
  }

  const config = getProviderConfig(storedState.provider);

  if (!config) {
    return { success: false, error: `Provider ${storedState.provider} not configured` };
  }

  try {
    // Exchange code for tokens
    // Redirect flow needs backend exchange since it doesn't use PKCE
    if (!options?.backendUrl) {
      return { success: false, error: 'Backend URL required for redirect flow token exchange' };
    }

    const response = await fetch(options.backendUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        provider: storedState.provider,
        code,
        redirectUri: storedState.redirectUri,
      }),
    });

    if (!response.ok) {
      const error = await response.json().catch(() => ({}));
      return { success: false, error: error.message || 'Token exchange failed' };
    }

    const tokenResponse = await response.json();

    // Get user info
    const userInfo = await fetchProviderUserInfo(
      storedState.provider,
      tokenResponse.access_token
    );

    // Verify actual granted scopes (GitHub via header, Google via tokeninfo, others pass-through)
    const { scopes: actualScopes, warning: scopeWarning } = await resolveActualScopes(
      storedState.provider,
      tokenResponse.access_token,
      storedState.scopes,
    );

    // Create connection
    const callbackClientId = config.webClientId || config.clientId;
    const connection = createOAuthConnection(
      storedState.provider,
      userInfo.providerId,
      userInfo.email,
      tokenResponse.access_token,
      actualScopes,
      {
        name: userInfo.name,
        avatarUrl: userInfo.avatarUrl,
        refreshToken: tokenResponse.refresh_token,
        expiresAt: tokenResponse.expires_at ?? computeTokenExpiresAt(storedState.provider, tokenResponse.expires_in),
        label: storedState.label,
        authMethod: 'web_oauth', // Web callback flow is always web auth
        issuedByClientId: callbackClientId,
      }
    );

    return { success: true, connection, warning: scopeWarning };
  } catch (error) {
    return {
      success: false,
      error: error instanceof Error ? error.message : 'Failed to complete OAuth flow',
    };
  }
}

/**
 * Fetch user info from provider
 */
async function fetchProviderUserInfo(
  provider: OAuthProvider,
  accessToken: string
): Promise<{
  providerId: string;
  email: string;
  name?: string;
  avatarUrl?: string;
}> {
  // Try to get user info URL from registry first
  const metadata = getProviderMetadata(provider);
  const url = metadata?.userInfoUrl;

  if (!url) {
    throw new Error(`User info not available for ${provider}`);
  }

  // Slack requires two API calls: auth.test (identity) + users.info (profile/email)
  if (provider === 'slack') {
    const testResp = await fetch('https://slack.com/api/auth.test', {
      headers: { Authorization: `Bearer ${accessToken}` },
    });
    const testData = await testResp.json();
    if (!testData.ok) throw new Error(`Slack auth.test failed: ${testData.error}`);

    const userResp = await fetch(`https://slack.com/api/users.info?user=${testData.user_id}`, {
      headers: { Authorization: `Bearer ${accessToken}` },
    });
    const userData = await userResp.json();
    const profile = userData.user?.profile;

    return {
      providerId: testData.user_id,
      email: profile?.email || '',
      name: profile?.real_name || profile?.display_name,
      avatarUrl: profile?.image_72,
    };
  }

  const response = await fetch(url, {
    headers: { Authorization: `Bearer ${accessToken}` },
  });

  if (!response.ok) {
    throw new Error(`Failed to fetch user info: ${response.status}`);
  }

  const data = await response.json();

  // Normalize response across providers
  // Each provider has different field names for the same data
  return normalizeUserInfo(provider, data);
}

/**
 * Normalize user info response from different providers
 */
function normalizeUserInfo(
  provider: OAuthProvider,
  data: Record<string, unknown>
): {
  providerId: string;
  email: string;
  name?: string;
  avatarUrl?: string;
} {
  // Provider-specific field mappings
  switch (provider) {
    case 'google':
      return {
        providerId: data.sub as string,
        email: data.email as string,
        name: data.name as string | undefined,
        avatarUrl: data.picture as string | undefined,
      };

    case 'microsoft':
      return {
        providerId: data.id as string,
        email: (data.mail || data.userPrincipalName) as string,
        name: data.displayName as string | undefined,
      };

    case 'github':
      return {
        providerId: String(data.id),
        email: data.email as string,
        name: (data.name || data.login) as string | undefined,
        avatarUrl: data.avatar_url as string | undefined,
      };

    case 'discord':
      return {
        providerId: data.id as string,
        email: data.email as string,
        name: (data.global_name || data.username) as string | undefined,
        avatarUrl: data.avatar
          ? `https://cdn.discordapp.com/avatars/${data.id}/${data.avatar}.png`
          : undefined,
      };

    case 'slack':
      return {
        providerId: (data.user as Record<string, unknown>)?.id as string,
        email: (data.user as Record<string, unknown>)?.email as string,
        name: (data.user as Record<string, unknown>)?.name as string | undefined,
        avatarUrl: (data.user as Record<string, unknown>)?.image_72 as string | undefined,
      };

    case 'notion': {
      const owner = data.owner as Record<string, unknown> | undefined;
      const user = owner?.user as Record<string, unknown> | undefined;
      return {
        providerId: (user?.id as string) ?? (data.workspace_id as string) ?? '',
        email: '', // Notion doesn't provide email in OAuth response
        name: user?.name as string | undefined,
        avatarUrl: user?.avatar_url as string | undefined,
      };
    }

    case 'linear':
      return {
        providerId: data.id as string,
        email: data.email as string,
        name: data.name as string | undefined,
        avatarUrl: data.avatarUrl as string | undefined,
      };

    case 'asana':
      return {
        providerId: data.gid as string,
        email: data.email as string,
        name: data.name as string | undefined,
        avatarUrl: (data.photo as Record<string, unknown>)?.image_128x128 as string | undefined,
      };

    // Generic fallback for providers with standard OIDC claims
    default:
      return {
        providerId: (data.sub || data.id || data.user_id || '') as string,
        email: (data.email || '') as string,
        name: (data.name || data.display_name || data.username) as string | undefined,
        avatarUrl: (data.picture || data.avatar_url || data.avatar) as string | undefined,
      };
  }
}

// =============================================================================
// TOKEN REFRESH
// =============================================================================

/**
 * Refresh an OAuth connection's tokens
 * Supports:
 * - Chrome identity refresh (for Google connections without refresh token in extension)
 * - Backend-based refresh
 * - Direct refresh for PKCE-enabled providers
 *
 * NOTE: This function has built-in locking to prevent concurrent refreshes for the same connection.
 * If a refresh is already in progress, subsequent calls will wait for it to complete.
 */
export async function refreshConnection(
  connection: OAuthConnection,
  options?: {
    backendUrl?: string;
    clientId?: string; // Required for direct refresh
    /** BYOA: user-supplied `client_secret`. Forces direct exchange (no relay). */
    clientSecret?: string;
  }
): Promise<RefreshConnectionResult> {
  const connectionId = connection.id;

  // If a refresh is already in progress for this connection, wait for it
  if (inFlightRefreshes.has(connectionId)) {
    logger.debug(`[OAuth] Refresh already in progress for ${connectionId}, waiting...`);
    return await inFlightRefreshes.get(connectionId)!;
  }

  // Create the refresh promise and store it to prevent concurrent refreshes
  const refreshPromise = performRefresh(connection, options);
  inFlightRefreshes.set(connectionId, refreshPromise);

  try {
    return await refreshPromise;
  } finally {
    // Clean up the in-flight tracking
    inFlightRefreshes.delete(connectionId);
  }
}

/**
 * When a Google token refresh fails with unauthorized_client, the refresh token
 * was likely issued by a different PF client_id (e.g., legacy vs friction-free).
 * Try each other PF web client ID via the relay until one works.
 * On success, updates issuedByClientId so future refreshes go straight to the right one.
 */
async function retryRefreshWithAlternateClients(
  connection: OAuthConnection,
  failedClientId: string,
): Promise<RefreshConnectionResult | null> {
  // Collect all PF web (primary) client IDs, excluding the one that already failed
  const alternateClientIds = Object.values(GOOGLE_SCOPE_ROUTING.apps)
    .map(app => app.clientId)
    .filter(id => id !== failedClientId);

  if (alternateClientIds.length === 0) return null;

  logger.info('[OAuth] unauthorized_client — retrying with alternate PF client IDs:', alternateClientIds);

  for (const altClientId of alternateClientIds) {
    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 15_000);
      let response: Response;
      try {
        response = await fetch(`${PRIVATE_RELAY_BASE_URL}/api/oauth/token`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },
          body: JSON.stringify({
            provider: 'google',
            client_id: altClientId,
            grant_type: 'refresh_token',
            refresh_token: connection.refreshToken,
          }),
          signal: controller.signal,
        });
      } catch (err) {
        if (err instanceof DOMException && err.name === 'AbortError') continue;
        throw err;
      } finally {
        clearTimeout(timeoutId);
      }

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        logger.debug('[OAuth] Alternate client %s also failed: %s', altClientId, errorData.error || response.status);
        continue;
      }

      const data = await response.json();
      const newAccessToken = data.access_token;
      const newRefreshToken = data.refresh_token ?? connection.refreshToken;
      const newExpiresAt = computeTokenExpiresAt('google', data.expires_in);

      await savePendingRefreshToken(connection.id, newAccessToken, newRefreshToken, newExpiresAt, altClientId);

      const updatedConnection: OAuthConnection = {
        ...connection,
        accessToken: newAccessToken,
        refreshToken: newRefreshToken,
        expiresAt: newExpiresAt,
        lastRefreshedAt: Date.now(),
        status: 'active',
        // Self-heal: record the correct client_id so future refreshes skip the retry
        issuedByClientId: altClientId,
      };

      applyTokenClientUpdate(updatedConnection, connection, altClientId, newAccessToken, newRefreshToken, newExpiresAt);

      logger.info('[OAuth] Token refresh succeeded with alternate client %s (self-healed issuedByClientId)', altClientId);
      return { success: true, connection: updatedConnection };
    } catch (err) {
      logger.warn('[OAuth] Error trying alternate client %s:', altClientId, err);
    }
  }

  return null; // All alternates failed
}

/**
 * Internal function that performs the actual token refresh.
 * This is separated from refreshConnection to allow the locking logic to wrap it.
 */
async function performRefresh(
  connection: OAuthConnection,
  options?: {
    backendUrl?: string;
    clientId?: string;
    /** BYOA: user-supplied `client_secret`. Forces direct exchange (no relay). */
    clientSecret?: string;
  }
): Promise<RefreshConnectionResult> {
  // Legacy chrome_identity connections that never received a refresh_token (tokens
  // were managed by chrome.identity.getAuthToken) cannot be silently migrated to
  // the web_oauth client_id — Google only returns refresh_token on interactive
  // consent. Flag these as expired so the UI surfaces the Reconnect button; the
  // Reconnect flow creates a fresh web_oauth connection.
  //
  // A merged chrome_identity connection that DOES have a refreshToken (from a
  // web_oauth tokenClient merge) falls through to the standard web OAuth refresh
  // path below.
  if (!connection.refreshToken) {
    return {
      success: false,
      error: connection.authMethod === 'chrome_identity'
        ? 'This connection uses a legacy auth method. Please reconnect your account.'
        : 'No refresh token available. Please disconnect and reconnect the account.',
      connection: { ...connection, status: 'expired' },
    };
  }

  const config = getProviderConfig(connection.provider);
  const metadata = PROVIDER_REGISTRY[connection.provider];

  if (!config && !metadata) {
    return { success: false, error: `Provider ${connection.provider} not configured` };
  }

  try {
    // Refresh via backend if URL provided
    if (options?.backendUrl) {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 15_000);
      let response: Response;
      try {
        response = await fetch(options.backendUrl, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            provider: connection.provider,
            refreshToken: connection.refreshToken,
          }),
          signal: controller.signal,
        });
      } catch (err) {
        if (err instanceof DOMException && err.name === 'AbortError') {
          return { success: false, error: 'Token refresh timed out after 15 seconds' };
        }
        throw err;
      } finally {
        clearTimeout(timeoutId);
      }

      if (!response.ok) {
        const error = await response.json().catch(() => ({}));
        return { success: false, error: error.message || 'Token refresh failed' };
      }

      const data = await response.json();

      const newAccessToken = data.access_token;
      const newRefreshToken = data.refresh_token ?? connection.refreshToken;
      const newExpiresAt = data.expires_at ?? computeTokenExpiresAt(connection.provider, data.expires_in);

      const updatedConnection: OAuthConnection = {
        ...connection,
        accessToken: newAccessToken,
        refreshToken: newRefreshToken,
        expiresAt: newExpiresAt,
        lastRefreshedAt: Date.now(),
        status: 'active',
      };

      // Update tokenClients to keep them in sync with flat fields
      applyTokenClientUpdate(
        updatedConnection, connection,
        options?.clientId || connection.issuedByClientId,
        newAccessToken, newRefreshToken, newExpiresAt,
      );

      return { success: true, connection: updatedConnection };
    }

    // Direct refresh using refresh token
    const tokenUrl = metadata?.tokenUrl;

    // Determine client ID: explicit override, then issuedByClientId (iOS PKCE), then config fallback.
    const clientId = options?.clientId || connection.issuedByClientId || config?.webClientId || config?.clientId;

    // Detect native/PKCE clients (e.g., iOS) which don't use a client_secret.
    // Also check PF scope routing — a PF web (primary) client needs the relay + secret,
    // even if it doesn't match config.webClientId (e.g., legacy client from a different GCP project).
    const pfApp = connection.issuedByClientId ? getPfAppByClientId(connection.issuedByClientId) : null;
    const isPfWebClient = pfApp && connection.issuedByClientId === pfApp.clientId;
    const isNativeClient =
      connection.issuedByClientId &&
      !isPfWebClient &&
      connection.issuedByClientId !== config?.webClientId &&
      connection.issuedByClientId !== config?.clientId;

    if (!tokenUrl) {
      return { success: false, error: 'No token URL available for provider' };
    }

    if (!clientId) {
      return { success: false, error: 'Client ID required for direct token refresh' };
    }

    logger.debug('[OAuth] Attempting direct token refresh for', connection.provider);

    // BYOA path: caller-supplied client_secret wins; otherwise look it up in
    // the BYOA registry when `issuedByClientId` belongs to a user-registered
    // app. This lets background/tool-middleware callers — which don't know
    // whether a connection is BYOA — refresh without a special code path.
    let byoaSecret = options?.clientSecret;
    if (!byoaSecret && clientId) {
      try {
        const settings = await getStorageAdapter().getSettings();
        byoaSecret = getByoaClientSecret(clientId, settings);
      } catch {
        // No settings available (e.g., early boot): direct refresh will fail
        // with invalid_client, which the caller handles by prompting reauth.
      }
    }
    const useRelay = RELAY_PROXIED_PROVIDERS.has(connection.provider) && !isNativeClient && !byoaSecret;

    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 15_000);
    let response: Response;
    try {
      if (useRelay) {
        // PebbleFlow-owned provider — proxy through relay (secret injected server-side)
        response = await fetch(`${PRIVATE_RELAY_BASE_URL}/api/oauth/token`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },
          body: JSON.stringify({
            provider: connection.provider,
            client_id: clientId,
            grant_type: 'refresh_token',
            refresh_token: connection.refreshToken,
          }),
          signal: controller.signal,
        });
      } else {
        // BYOA, native client (no secret needed), or user-configured provider
        const refreshBody: Record<string, string> = {
          client_id: clientId,
          grant_type: 'refresh_token',
          refresh_token: connection.refreshToken,
        };
        const secret = byoaSecret ?? (isNativeClient ? undefined : (config?.clientSecret || config?.webClientSecret));
        if (secret) refreshBody.client_secret = secret;

        response = await fetch(tokenUrl, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
            // GitHub requires Accept: application/json to return JSON instead of form-urlencoded
            'Accept': 'application/json',
          },
          body: new URLSearchParams(refreshBody),
          signal: controller.signal,
        });
      }
    } catch (err) {
      if (err instanceof DOMException && err.name === 'AbortError') {
        return { success: false, error: 'Token refresh timed out after 15 seconds' };
      }
      throw err;
    } finally {
      clearTimeout(timeoutId);
    }

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      const errorMessage = errorData.error_description || errorData.error || 'Token refresh failed';

      // Check for invalid_grant which means refresh token is revoked/expired
      if (errorData.error === 'invalid_grant') {
        return {
          success: false,
          error: 'Refresh token expired or revoked. Please reconnect your account.',
        };
      }

      // unauthorized_client: the refresh token was issued by a different client_id.
      // This happens for legacy connections created before the friction-free migration.
      // Try other PF web client IDs via the relay before giving up.
      if (errorData.error === 'unauthorized_client' && connection.provider === 'google') {
        const retryResult = await retryRefreshWithAlternateClients(connection, clientId);
        if (retryResult) return retryResult;
      }

      return { success: false, error: errorMessage };
    }

    const data = await response.json();

    const newRefreshToken = data.refresh_token ?? connection.refreshToken;
    const newAccessToken = data.access_token;
    const newExpiresAt = computeTokenExpiresAt(connection.provider, data.expires_in);

    // CRITICAL: Save the new tokens to the write-ahead log BEFORE returning.
    // This ensures that if we crash before the main connection is persisted,
    // we still have the new refresh token saved. Some providers rotate refresh
    // tokens on every use, so losing one means losing access forever.
    await savePendingRefreshToken(connection.id, newAccessToken, newRefreshToken, newExpiresAt, options?.clientId || connection.issuedByClientId);

    // Backfill email if missing (legacy connections created without identity scopes).
    // We just got a fresh access token, so fetch userinfo opportunistically.
    let backfilledEmail = connection.email;
    let backfilledName = connection.name;
    if (!connection.email && newAccessToken) {
      const userInfo = await fetchUserInfo(connection.provider, newAccessToken).catch(() => null);
      if (userInfo?.email) {
        backfilledEmail = userInfo.email;
        backfilledName = backfilledName || userInfo.name;
        logger.info('[OAuth] Backfilled missing email during refresh:', userInfo.email);
      }
    }

    let updatedConnection: OAuthConnection = {
      ...connection,
      email: backfilledEmail,
      name: backfilledName,
      accessToken: newAccessToken,
      refreshToken: newRefreshToken,
      expiresAt: newExpiresAt,
      lastRefreshedAt: Date.now(),
      status: 'active',
    };

    // Update the matching tokenClient if tokenClients exist.
    // Without this, tokenClients retain stale tokens and the next call
    // via getTokenClientForScopes returns an expired token.
    applyTokenClientUpdate(
      updatedConnection, connection,
      options?.clientId || connection.issuedByClientId,
      newAccessToken, newRefreshToken, newExpiresAt,
    );

    logger.debug('[OAuth] Token refresh successful');
    return { success: true, connection: updatedConnection };
  } catch (error) {
    logger.error('[OAuth] Token refresh error:', error);
    return {
      success: false,
      error: error instanceof Error ? error.message : 'Refresh failed',
    };
  }
}

// =============================================================================
// CONNECTION UTILITIES
// =============================================================================

/**
 * Get all connections from a user profile
 * OAuth connections are now profile-scoped (not shared across profiles)
 */
export function getConnections(profile: UserProfile): OAuthConnection[] {
  return profile.oauthConnections ?? [];
}

/**
 * Get connections for a specific provider
 */
export function getProviderConnections(
  profile: UserProfile,
  provider: OAuthProvider
): OAuthConnection[] {
  return getConnectionsByProvider(profile.oauthConnections, provider);
}

/**
 * Find a connection by ID
 */
export function getConnectionById(
  profile: UserProfile,
  connectionId: string
): OAuthConnection | undefined {
  return findOAuthConnectionById(profile.oauthConnections, connectionId);
}

/**
 * Find a connection by provider and email
 */
export function getConnectionByProviderEmail(
  profile: UserProfile,
  provider: OAuthProvider,
  email?: string
): OAuthConnection | undefined {
  return findOAuthConnection(profile.oauthConnections, provider, email);
}

/**
 * Check health of all connections
 */
export function checkConnectionsHealth(profile: UserProfile): ConnectionHealth[] {
  const connections = getConnections(profile);
  const now = Date.now();

  return connections.map((conn) => {
    // Refresh requires a refresh_token. Legacy chrome_identity connections
    // without one surface as needs-Reconnect (handled by the UI expired path).
    const canRefresh = !!conn.refreshToken;

    return {
      connectionId: conn.id,
      provider: conn.provider,
      status: conn.status,
      isTokenExpired: isOAuthTokenExpired(conn, 0),
      canRefresh,
      lastChecked: now,
    };
  });
}

/**
 * Get connections that need refresh
 */
export function getConnectionsNeedingRefresh(
  profile: UserProfile,
  bufferMs: number = 5 * 60 * 1000
): OAuthConnection[] {
  return getConnections(profile).filter((conn) => {
    if (conn.status !== 'active' || !isOAuthTokenExpired(conn, bufferMs)) {
      return false;
    }

    // Refresh requires a refresh_token. Legacy chrome_identity connections
    // without one need a manual Reconnect (handled by the UI expired path).
    return !!conn.refreshToken;
  });
}

/**
 * Get a valid access token for a connection, automatically refreshing if expired
 * Returns the updated connection if refreshed, or null if refresh failed
 *
 * This function deduplicates concurrent refresh requests for the same connection
 * to prevent race conditions when multiple tools request tokens simultaneously.
 */
export async function getValidAccessToken(
  connection: OAuthConnection,
  options?: {
    clientId?: string;
    bufferMs?: number; // Default 5 minutes
  }
): Promise<{ accessToken: string; connection: OAuthConnection } | null> {
  const bufferMs = options?.bufferMs ?? 5 * 60 * 1000;

  // Providers with non-expiring tokens (e.g., GitHub) — always valid, skip refresh
  const providerMeta = PROVIDER_REGISTRY[connection.provider];
  if (providerMeta?.tokenNeverExpires) {
    return { accessToken: connection.accessToken, connection };
  }

  // Check if token is still valid
  if (!isOAuthTokenExpired(connection, bufferMs)) {
    return { accessToken: connection.accessToken, connection };
  }

  // Token expired or about to expire - try to refresh
  logger.debug('[OAuth] Token expired for', connection.provider, '- attempting refresh');

  // All refreshable connections need a refresh_token. Legacy chrome_identity
  // connections without one are treated as expired — the UI will surface the
  // Reconnect button and users get a fresh web_oauth connection on reconnect.
  if (!connection.refreshToken) {
    logger.warn('[OAuth] No refresh token available for connection', connection.provider);

    notifyConnectionNeedsReauth(
      connection,
      'No refresh token available. Please reconnect your account to continue using this integration.',
      undefined
    );

    return null;
  }

  // Check if a previous refresh was interrupted by service worker termination.
  // If so, wait briefly to avoid double-refresh (the previous refresh may have
  // succeeded server-side and we just didn't persist the new tokens).
  const wasInterrupted = await wasRefreshInterrupted(connection.id);
  if (wasInterrupted) {
    logger.debug('[OAuth] Skipping refresh - previous refresh may have been interrupted');
    // Return the existing token even if it might be stale - better than double-refresh
    return { accessToken: connection.accessToken, connection };
  }

  // Track refresh in persistent storage (survives service worker restarts)
  // Note: refreshConnection() now handles in-memory locking internally
  await trackInFlightRefresh(connection.id);

  try {
    // refreshConnection() has built-in locking to prevent concurrent refreshes
    const result = await refreshConnection(connection, { clientId: options?.clientId });

    if (result.success && result.connection) {
      return { accessToken: result.connection.accessToken, connection: result.connection };
    }

    // Persist downgraded connection even on failure (e.g., Chrome profile mismatch
    // downgrades authMethod from chrome_identity to web_oauth) so subsequent
    // refreshes don't retry the wrong path.
    if (!result.success && result.connection) {
      notifyConnectionRefreshed(result.connection, undefined);
    }

    logger.error('[OAuth] Token refresh failed:', result.error);

    // Notify that this connection needs re-authorization
    // This allows the UI to prompt the user to reconnect
    notifyConnectionNeedsReauth(
      connection,
      result.error || 'Token refresh failed. Please reconnect your account.',
      undefined // profileId will be resolved by the callback handler
    );

    return null;
  } finally {
    // Clean up the persistent in-flight tracking
    // Note: refreshConnection() cleans up in-memory tracking internally
    await clearInFlightRefresh(connection.id);
  }
}

/**
 * Get a valid access token for any OAuth connection.
 *
 * Provider-agnostic wrapper around getValidAccessToken that:
 * 1. Auto-resolves client ID from the provider registry
 * 2. Checks expiry with 5-minute buffer
 * 3. Refreshes if needed
 * 4. Persists refreshed tokens via notifyConnectionRefreshed
 *
 * This is the recommended way for ALL features (not just Google tools)
 * to get an access token from an OAuthConnection.
 */
export async function getAccessTokenForConnection(
  connection: OAuthConnection,
  options?: {
    force?: boolean;
    profileId?: string;
    requiredScopes?: string[];
  }
): Promise<string | null> {
  // When requiredScopes is provided and tokenClients exist, pick the best client
  const selectedClient = options?.requiredScopes
    ? getTokenClientForScopes(connection, options.requiredScopes)
    : undefined;

  // Use the selected client's token if available, otherwise fall back to flat fields
  const effectiveAccessToken = selectedClient?.accessToken ?? connection.accessToken;
  const effectiveExpiresAt = selectedClient?.expiresAt ?? connection.expiresAt;

  const providerMeta = PROVIDER_REGISTRY[connection.provider];
  const needsRefresh = !providerMeta?.tokenNeverExpires && (
    options?.force ||
    effectiveExpiresAt < Date.now() + 5 * 60 * 1000 ||
    effectiveAccessToken === OAUTH_PLACEHOLDER_TOKEN
  );

  if (!needsRefresh) {
    return effectiveAccessToken;
  }

  const config = getProviderConfig(connection.provider);
  // When a specific tokenClient was selected, use its clientId for refresh
  const clientId = selectedClient?.clientId
    || connection.issuedByClientId || config?.webClientId || config?.clientId;

  // When a specific tokenClient was selected, create a view of the connection
  // that uses that client's tokens so getValidAccessToken checks the right expiry.
  // Without this, getValidAccessToken checks the flat connection.expiresAt which
  // may belong to a different (fresh) client, causing it to return the wrong token.
  if (selectedClient && !selectedClient.refreshToken && selectedClient.expiresAt && selectedClient.expiresAt < Date.now() + 5 * 60 * 1000) {
    logger.warn('[OAuth] Selected tokenClient has no refreshToken, falling back to flat refreshToken.',
      'clientId:', selectedClient.clientId, 'flatIssuedBy:', connection.issuedByClientId);
  }
  const connectionForRefresh = selectedClient
    ? {
        ...connection,
        accessToken: selectedClient.accessToken,
        refreshToken: selectedClient.refreshToken || connection.refreshToken,
        expiresAt: selectedClient.expiresAt ?? connection.expiresAt,
      }
    : connection;

  const result = await getValidAccessToken(connectionForRefresh, {
    clientId: clientId || undefined,
  });

  if (!result) {
    logger.warn('[OAuth] Token refresh failed for', connection.provider, connection.email);
    return null;
  }

  // Persist refreshed connection if tokens changed.
  // Compare against connectionForRefresh (not the original connection) because
  // the synthetic view is what getValidAccessToken received — if it returned the
  // same object, no refresh occurred and we must not persist the synthetic flat fields.
  if (result.connection !== connectionForRefresh) {
    notifyConnectionRefreshed(result.connection, options?.profileId);
  }

  return result.accessToken;
}

/**
 * Remove a connection from profile (marks as deleted tombstone for sync)
 * Returns updated connections array with the connection marked as deleted
 */
export function removeConnection(
  profile: UserProfile,
  connectionId: string
): OAuthConnection[] {
  return (profile.oauthConnections ?? []).map((c) =>
    c.id === connectionId
      ? { ...c, deleted: true, deletedAt: Date.now(), status: 'revoked' as const }
      : c
  );
}

/**
 * Revoke a Google OAuth token at Google's servers.
 *
 * This calls Google's revoke endpoint which invalidates the token entirely
 * (Google does not support granular per-scope revocation).
 * Also clears any Chrome Identity cached tokens if in extension context.
 *
 * Invalidate scopes on a stored connection after a server-side revocation.
 *
 * When a user revokes Google permissions from their Google Account settings,
 * the locally stored OAuthConnection still reports the scopes as granted.
 * This causes connectionHasScopes() to pass, skipping re-auth, and every
 * subsequent API call 403s with no recovery path.
 *
 * Call this when a Google API call returns 401/403 to:
 * 1. Remove the revoked scopes from the stored connection
 * 2. Expire the access token (forces refresh on next use)
 * 3. Persist changes so connectionHasScopes() correctly triggers re-auth
 *
 * If no scopes are specified, ALL scopes are cleared (full revocation).
 */
export async function invalidateConnectionScopes(
  connection: OAuthConnection,
  scopes?: string[],
): Promise<void> {
  const storage = getStorageAdapter();
  const profile = await storage.getCurrentProfile();
  if (!profile?.oauthConnections) return;

  const idx = profile.oauthConnections.findIndex(c => c.id === connection.id);
  if (idx < 0) return;

  const existing = profile.oauthConnections[idx];
  const scopeSet = scopes ? new Set(scopes) : null;
  const updatedScopes = scopeSet
    ? existing.scopes.filter(s => !scopeSet.has(s))
    : [];

  const updatedConn: OAuthConnection = {
    ...existing,
    scopes: updatedScopes,
    expiresAt: 0, // Force token refresh on next use
  };

  const updatedConns = [...profile.oauthConnections];
  updatedConns[idx] = updatedConn;

  logger.warn('[OAuth] Invalidated scopes on connection', connection.email,
    scopes ? `removed: ${scopes.join(', ')}` : 'cleared all scopes');

  await storage.updateProfile(profile.id, { oauthConnections: updatedConns });
}

/**
 * Best-effort: logs warnings on failure but does not throw, since the local
 * connection removal should still proceed even if the revoke request fails
 * (e.g., token already expired, network error).
 */
export async function revokeGoogleConnection(connection: OAuthConnection): Promise<void> {
  const token = connection.accessToken;
  if (!token) {
    logger.debug('[OAuth] No access token to revoke for:', connection.email);
    return;
  }

  // Revoke at Google's endpoint
  try {
    const response = await fetch(`https://oauth2.googleapis.com/revoke?token=${encodeURIComponent(token)}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    });
    if (response.ok) {
      logger.info('[OAuth] Successfully revoked Google token for:', connection.email);
    } else {
      // 400 = token already invalid/expired — that's fine
      const body = await response.text().catch(() => '');
      logger.warn('[OAuth] Google revoke returned', response.status, body);
    }
  } catch (error) {
    logger.warn('[OAuth] Failed to revoke Google token (network error):', error);
  }

  // Also clear Chrome Identity cached token if in extension context
  if (isExtensionContext() && typeof chrome !== 'undefined' && chrome?.identity?.removeCachedAuthToken) {
    try {
      await new Promise<void>((resolve) => {
        chrome.identity.removeCachedAuthToken({ token }, () => resolve());
      });
      logger.debug('[OAuth] Cleared Chrome Identity cached token');
    } catch {
      // Non-fatal
    }
  }
}

/**
 * Add or update a connection in profile (returns updated connections array)
 */
export function upsertConnection(
  profile: UserProfile,
  connection: OAuthConnection
): OAuthConnection[] {
  const connections = profile.oauthConnections ?? [];

  // Match by ID first, then fall back to natural key (provider + email)
  let existingIndex = connections.findIndex((c) => c.id === connection.id);
  if (existingIndex === -1 && connection.email) {
    existingIndex = connections.findIndex((c) =>
      !c.deleted &&
      c.provider === connection.provider &&
      c.email && c.email.toLowerCase() === connection.email.toLowerCase()
    );
  }

  if (existingIndex >= 0) {
    // Update existing
    const updated = [...connections];
    updated[existingIndex] = connection;
    return updated;
  } else {
    // Add new
    return [...connections, connection];
  }
}

// =============================================================================
// PROVIDER HELPERS
// =============================================================================

/**
 * Get display name for provider
 */
export function getProviderDisplayName(provider: OAuthProvider): string {
  const metadata = getProviderMetadata(provider);
  return metadata?.name ?? provider;
}

/**
 * Get icon name for provider (for UI)
 */
export function getProviderIcon(provider: OAuthProvider): string {
  const metadata = getProviderMetadata(provider);
  return metadata?.icon ?? provider;
}

/**
 * Get provider color (for UI)
 */
export function getProviderColor(provider: OAuthProvider): string | undefined {
  const metadata = getProviderMetadata(provider);
  return metadata?.color;
}

/**
 * Get available providers (configured for use)
 */
export function getAvailableProviders(): OAuthProvider[] {
  return Array.from(providerConfigs.keys());
}

/**
 * Get all providers in registry (pre-configured integrations)
 */
export function getRegisteredProviders(): OAuthProvider[] {
  return Object.keys(PROVIDER_REGISTRY) as OAuthProvider[];
}

/**
 * Get all supported providers (even if not configured)
 * @deprecated Use getRegisteredProviders() instead
 */
export function getSupportedProviders(): OAuthProvider[] {
  return getRegisteredProviders();
}

/**
 * Upgrade chrome_identity Google connections that lack refresh tokens.
 *
 * chrome.identity.getAuthToken never returns refresh tokens, so connections
 * created via Chrome extension cannot be refreshed outside the extension.
 * On native platforms (macOS/iOS) with platformOAuthHandler, we can silently
 * re-authenticate via ASWebAuthenticationSession to obtain a refresh token,
 * upgrading the connection for standalone use.
 *
 * Call this from the UI layer after storage is available and platformOAuthHandler
 * is registered (e.g., after bootMacOSApp).
 */
export async function upgradeStaleNativeConnections(
  connections: OAuthConnection[],
  saveConnection: (connection: OAuthConnection) => Promise<void>,
): Promise<void> {
  if (!platformOAuthHandler) return;

  const staleGoogleConnections = connections.filter(
    c => c.provider === 'google' &&
         c.authMethod === 'chrome_identity' &&
         !c.refreshToken
  );

  if (staleGoogleConnections.length === 0) return;

  logger.info('[OAuth] Found %d chrome_identity connection(s) without refresh tokens — upgrading via platform OAuth', staleGoogleConnections.length);

  for (const connection of staleGoogleConnections) {
    try {
      const result = await platformOAuthHandler('google', connection.scopes || ['openid', 'email', 'profile'], {
        loginHint: connection.email,
      });

      if (result.connection?.refreshToken) {
        const upgraded: OAuthConnection = {
          ...connection,
          accessToken: result.connection.accessToken,
          refreshToken: result.connection.refreshToken,
          expiresAt: result.connection.expiresAt || Date.now() + 3600 * 1000,
          lastRefreshedAt: Date.now(),
          status: 'active',
          authMethod: 'web_oauth',
          issuedByClientId: result.connection.issuedByClientId || connection.issuedByClientId,
        };
        await saveConnection(upgraded);
        logger.info('[OAuth] Successfully upgraded connection for %s to web_oauth with refresh token', connection.email);
      }
    } catch (err) {
      logger.warn('[OAuth] Failed to upgrade connection for %s:', connection.email, err);
      // Non-fatal — the user can manually reconnect later
    }
  }
}
